(window.webpackJsonp=window.webpackJsonp||[]).push([[39],{666:function(n,e){n.exports="\x3c!-- \ntitle: 22-Centos部署Nginx\nsort: \n--\x3e \n# CentOS安装Nginx\n\n- Nginx 是一个高性能的HTTP和反向代理web服务器。\n\n## 安装\n\n- yum安装：\n\n  ```bash\n  sudo yum -y install nginx\t\t# 安装nginx\n  sudo yum remove nginx\t\t\t# 卸载nginx\n  ```\n\n- 配置nginx服务：\n\n  ```bash\n  sudo systemctl enable nginx \t# 设置开机启动 \n  sudo service nginx start \t\t# 启动 nginx 服务\n  sudo service nginx stop \t\t# 停止 nginx 服务\n  sudo service nginx restart \t\t# 重启 nginx 服务\n  sudo service nginx reload \t\t# 重新加载配置\n  ```\n\n- 查看是否设置成功：\n\n  ```bash\n  ps -ef | grep nginx\n  ```\n\n## 配置文件\n\n- nginx.conf说明：\n\n```bash\n# user  nobody;\nworker_processes  1; # 工作进程：数目。根据硬件调整，通常等于cpu数量或者2倍cpu数量。\n \n# 错误日志存放路径\n# error_log  logs/error.log;\n# error_log  logs/error.log  notice;\n# error_log  logs/error.log  info;\n \n# pid        logs/nginx.pid; \t# nginx进程pid存放路径\n \n \nevents {\n    worker_connections  1024; \t# 工作进程的最大连接数量\n}\n \n \nhttp {\n    include       mime.types; \t# 指定mime类型，由mime.type来定义\n    default_type  application/octet-stream;\n \n    # 日志格式设置\n    # log_format  main  '$remote_addr - $remote_user [$time_local] \"$request\" '\n    #                  '$status $body_bytes_sent \"$http_referer\" '\n    #                  '\"$http_user_agent\" \"$http_x_forwarded_for\"';\n \n    #access_log  logs/access.log  main; #用log_format指令设置日志格式后，需要用access_log来指定日志文件存放路径\n\t\t\t\t\t\n    sendfile        on; # 指定nginx是否调用sendfile函数来输出文件，对于普通应用，必须设置on。\n\t\t\t如果用来进行下载等应用磁盘io重负载应用，可设着off，以平衡磁盘与网络io处理速度，降低系统uptime。\n    # tcp_nopush     on; # 此选项允许或禁止使用socket的TCP_CORK的选项，此选项仅在sendfile的时候使用\n \n    # keepalive_timeout  0;  # keepalive超时时间\n    keepalive_timeout  65;\n \n    #gzip  on; # 开启gzip压缩服务\n \n    # 虚拟主机\n    server {\n        listen       80;  # 配置监听端口号\n        server_name  localhost; # 配置访问域名，域名可以有多个，用空格隔开\n \n        #charset koi8-r; # 字符集设置\n \n        #access_log  logs/host.access.log  main;\n \n        location / {\n            root   html;\n            index  index.html index.htm;\n        }\n        # 错误跳转页\n        # error_page  404              /404.html; \n \n        # redirect server error pages to the static page /50x.html\n        #\n        error_page   500 502 503 504  /50x.html;\n        location = /50x.html {\n            root   html;\n        }\n \n        # proxy the PHP scripts to Apache listening on 127.0.0.1:80\n        #\n        # location ~ \\.php$ {\n        #    proxy_pass   http://127.0.0.1;\n        #}\n \n        # pass the PHP scripts to FastCGI server listening on 127.0.0.1:9000\n        #\n        # location ~ \\.php$ { #请求的url过滤，正则匹配，~为区分大小写，~*为不区分大小写。\n        #    root           html; #根目录\n        #    fastcgi_pass   127.0.0.1:9000; #请求转向定义的服务器列表\n        #    fastcgi_index  index.php; # 如果请求的Fastcgi_index URI是以 / 结束的, 该指令设置的文件会被附加到URI的后面并保存在变量$fastcig_script_name中\n        #    fastcgi_param  SCRIPT_FILENAME  /scripts$fastcgi_script_name;\n        #    include        fastcgi_params;\n        #}\n \n        # deny access to .htaccess files, if Apache's document root\n        # concurs with nginx's one\n        #\n        #location ~ /\\.ht {\n        #    deny  all;\n        #}\n    }\n \n \n    # another virtual host using mix of IP-, name-, and port-based configuration\n    #\n    #server {\n    #    listen       8000;\n    #    listen       somename:8080;\n    #    server_name  somename  alias  another.alias;\n \n    #    location / {\n    #        root   html;\n    #        index  index.html index.htm;\n    #    }\n    #}\n \n \n    # HTTPS server\n    #\n    #server {\n    #    listen       443 ssl;  #监听端口\n    #    server_name  localhost; #域名\n \n    #    ssl_certificate      cert.pem; #证书位置\n    #    ssl_certificate_key  cert.key; #私钥位置\n \n    #    ssl_session_cache    shared:SSL:1m;\n    #    ssl_session_timeout  5m; \n \n    #    ssl_ciphers  HIGH:!aNULL:!MD5; #密码加密方式\n    #    ssl_prefer_server_ciphers  on; # ssl_prefer_server_ciphers  on; #\n \n \n    #    location / {\n    #        root   html;\n    #        index  index.html index.htm;\n    #    }\n    #}\n \n}\n```"}}]);